sp_rectangle_menu_item.record_script:
var bannerAwaitingAssignmentOverdue = function(data){
  var u = gs.getUser().getID();

  var DaysSinceTaskWasUnassignedOrRejectedWarning = gs.getProperty("x_153465_discovert.#DaysSinceTaskWasUnassignedOrRejectedWarning");
  //------------------------------------------------------------------------------------------------------------------
  // Build the Filter using Task Manger OUs, OUs where member and GTA if they are in that role
  // Get the list of OUs where the current user is a Task Manager
  var primary_assigneeFilter = "primary_assigneeIN";
  var taskSystemSettings = new tasking_System_Settings_Scripts();
  primary_assigneeFilter += taskSystemSettings.getMyOUTaskManagers(u).join(",");

  var isGTA = gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin");
  if(isGTA)
    primary_assigneeFilter += "^ORprimary_assignee.tasking_authoritiesISEMPTY"

  var filter ='u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11';
  if(!isGTA){
    filter += '^' + primary_assigneeFilter;
  }
  filter += '^u_last_unassigned_dateRELATIVELE@dayofweek@ago@'+DaysSinceTaskWasUnassignedOrRejectedWarning; 

  var tbf = new TaskerBannerFilters();

  tbf.label = 'Awaiting Assignment Overdue';
  tbf.table = 'x_153465_discovert_route_task_instance';
  tbf.filter = filter;
  tbf.orderDesc = 'sys_updated_on';
  tbf.idField = 'sys_id';
  tbf.displayFieldName = 'task_name';
  tbf.linkView = 'sp';
  tbf.pageId = 'discovertasker_taskdetails';
  tbf.viewAllLinkTitle = gs.getMessage('View all requests');
  tbf.viewAllLinkPageId = 'discovertasker_detailsdrilldown';
  tbf.viewAllLinkView = 'sp';
  if(!isGTA){
    tbf.viewAllLinkFilter = primary_assigneeFilter+'^u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_dateRELATIVELE@dayofweek@ago@' + DaysSinceTaskWasUnassignedOrRejectedWarning; 
  } else {
    tbf.viewAllLinkFilter = 'u_last_unassigned_dateISNOTEMPTY^state=-5^ORstate=11^u_last_unassigned_dateRELATIVELE@dayofweek@ago@' + DaysSinceTaskWasUnassignedOrRejectedWarning; 
  }

  tbf.createBanner();
  data.items = tbf.items;
  data.record_watchers = tbf.record_watchers;
  data.count = tbf.count;

}

bannerAwaitingAssignmentOverdue(data);
